import {useState} from 'react';import './PlaylistAdder.css';export default function PlaylistAdder(){const[song,setSong]=useState('');const[artist,setArtist]=useState('');const[list,setList]=useState([]);const add=e=>{e.preventDefault();if(!song||!artist){alert('Enter Song and Artist');return;}setList([...list,{song,artist}]);setSong('');setArtist('');};return <div className='card p-3'><form onSubmit={add}><h3>🎵 Playlist</h3><input className='form-control mt-2' value={song} onChange={e=>setSong(e.target.value)} placeholder='Song'/><input className='form-control mt-2' value={artist} onChange={e=>setArtist(e.target.value)} placeholder='Artist'/><button className='btn btn-primary mt-3 w-100'>Add Song</button></form><ul className='list-group mt-3'>{list.map((i,k)=><li key={k} className='list-group-item'>{i.song} - {i.artist}</li>)}</ul></div>}